/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportwpInventarioItens-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&FilterFullText.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Filtrar") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&FilterFullText) EndIf
If not (&FilInvEmpCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Empresa") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilInvEmpCod EndIf
If not (&FilInvFilCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Filial") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilInvFilCod EndIf
If not (&FilInvAno.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Ano") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilInvAno EndIf
If not (&FilInvMes.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Mes") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case &FilInvMes = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Janeiro"
Case &FilInvMes = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Fevereiro"
Case &FilInvMes = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Março"
Case &FilInvMes = 4 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Abril"
Case &FilInvMes = 5 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Maio"
Case &FilInvMes = 6 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Junho"
Case &FilInvMes = 7 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Julho"
Case &FilInvMes = 8 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Agosto"
Case &FilInvMes = 9 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Setembro"
Case &FilInvMes = 10 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Outubro"
Case &FilInvMes = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Novembro"
Case &FilInvMes = 12 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Dezembro"
EndCase EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Ref." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Nome produto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Unt.Custo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Qtd.Inventário" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Custo Inventário" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Grupo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Grupo Nome"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&FirstDataCellRow = &CellRow + 1 For each Inventario.Produtos order InvProGraRefPadL when &OrderedBy = 1 order InvProNom when &OrderedBy = 2 AND &OrderedDsc = False order (InvProNom) when &OrderedBy = 2 AND &OrderedDsc = True order InvProGraRef when &OrderedBy = 3 AND &OrderedDsc = False order (InvProGraRef) when &OrderedBy = 3 AND &OrderedDsc = True order InvProVlrCus when &OrderedBy = 4 AND &OrderedDsc = False order (InvProVlrCus) when &OrderedBy = 4 AND &OrderedDsc = True order InvProQtd when &OrderedBy = 5 AND &OrderedDsc = False order (InvProQtd) when &OrderedBy = 5 AND &OrderedDsc = True order InvProQtdAtu when &OrderedBy = 6 AND &OrderedDsc = False order (InvProQtdAtu) when &OrderedBy = 6 AND &OrderedDsc = True order InvGrupHie when &OrderedBy = 7 AND &OrderedDsc = False order (InvGrupHie) when &OrderedBy = 7 AND &OrderedDsc = True order InvGrupNomCmp when &OrderedBy = 8 AND &OrderedDsc = False order (InvGrupNomCmp) when &OrderedBy = 8 AND &OrderedDsc = True
using DSwpInventarioItens(&FilterFullText, &FilInvEmpCod, &FilInvFilCod, &FilInvAno, &FilInvMes)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(InvProGraRef) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(InvProNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Number = InvProVlrCus &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = InvProQtd &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Number = InvProVlrCusTot &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = WWP_Export_SecureText(InvGrupHie) &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = WWP_Export_SecureText(InvGrupNomCmp)
Do 'AfterWriteLine'
Endfor Do 'WriteTotalizers'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteTotalizers'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow + 1, &FirstColumn + 0).Number = &CellRow + 1 - &FirstDataCellRow &ExcelDocument.Cells(&CellRow + 1, &FirstColumn + 3).Text = format(!"=SUM(%1%2:%1%3)", CHR(ASC(!'A') + 3), &FirstDataCellRow.ToString().Trim(), &CellRow.ToString().Trim()) &ExcelDocument.Cells(&CellRow + 1, &FirstColumn + 4).Text = format(!"=SUM(%1%2:%1%3)", CHR(ASC(!'A') + 4), &FirstDataCellRow.ToString().Trim(), &CellRow.ToString().Trim()) &ExcelDocument.Cells(&CellRow + 1, &FirstColumn, 1, 6).Italic = True &ExcelDocument.Cells(&CellRow + 1, &FirstColumn, 1, 6).Bold = True
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wpInventarioItensGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wpInventarioItensGridState")) Else &GridState.FromXml(&Session.Get(!"wpInventarioItensGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILTERFULLTEXT" &FilterFullText.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILINVEMPCOD" &FilInvEmpCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILINVFILCOD" &FilInvFilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILINVANO" &FilInvAno.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILINVMES" &FilInvMes.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
